221	/** Renders a mini detail-fetcher node that uses useMarket */
222	function NodeWithDetail({
223	  node,
224	  isFocus,
225	  animationClass,
226	}: {
227	  node: GraphNode;
228	  isFocus: boolean;
229	  animationClass?: string;
230	}) {
